                    password: '',
                    isAuth: false
                }
            ],
            cur_user
        }
        this.addUser = this.addUser.bind(this)
    }
    render() {
        return (
            <BrowserRouter>
                <Routes>
                    <Route onAdd={this.addUser} path="/registration" Component={SignUp} />
                    <Route path="/" Component={Auth} />
                    {this.state.isAuth && <Route path="home" Component={Home} />}
                    <Route path="*" Component={NotFound} />
                </Routes>
            </BrowserRouter>
        )
    }
    addUser() {
